CREATE TABLE heat_forecast_jakarta (
            adm4 TEXT,
            desa_kelurahan TEXT,
            kecamatan TEXT,
            kotkab TEXT,
            provinsi TEXT,
            latitude REAL,
            longitude REAL,
            timezone TEXT,
            local_datetime TEXT,
            temperature_c REAL,
            humidity_pct REAL,
            heat_index_c REAL,
            risk_level TEXT,
            weather_desc_en TEXT,
            analysis_date TEXT,
            fetched_at TEXT DEFAULT CURRENT_TIMESTAMP,
            PRIMARY KEY("local_datetime","adm4")
        );
